import { useEffect, useRef } from "react";
import "./ChatWindow.css";

function Tick({ status }) {
  if (status === "seen")      return <span className="tick seen">✓✓</span>;
  if (status === "delivered") return <span className="tick delivered">✓✓</span>;
  return <span className="tick sent">✓</span>;
}

function formatTime(date) {
  return new Date(date).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

function formatDate(date) {
  const d = new Date(date);
  const today = new Date();
  const yesterday = new Date(); yesterday.setDate(yesterday.getDate() - 1);
  if (d.toDateString() === today.toDateString())     return "Today";
  if (d.toDateString() === yesterday.toDateString()) return "Yesterday";
  return d.toLocaleDateString([], { month: "short", day: "numeric" });
}

export default function ChatWindow({ messages, currentUser, selectedFriend, typingUser }) {
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, typingUser]);

  // Group by date
  const grouped = [];
  let lastDate = null;
  (messages || []).forEach(msg => {
    const d = formatDate(msg.time || msg.createdAt);
    if (d !== lastDate) { grouped.push({ type: "divider", label: d }); lastDate = d; }
    grouped.push({ type: "msg", data: msg });
  });

  return (
    <div className="chat-window">
      {grouped.length === 0 && (
        <div className="cw-start">
          <div className="cw-start-avatar">
            {selectedFriend?.profilePic
              ? <img src={selectedFriend.profilePic} alt="" />
              : selectedFriend?.username?.[0]?.toUpperCase()
            }
          </div>
          <p className="cw-start-text">
            Start of your conversation with <strong>@{selectedFriend?.username}</strong>
          </p>
        </div>
      )}

      {grouped.map((item, i) => {
        if (item.type === "divider") return (
          <div key={i} className="date-divider">
            <span>{item.label}</span>
          </div>
        );

        const msg   = item.data;
        const isMine = msg.sender === currentUser.username;

        return (
          <div key={msg._id || i} className={`msg-row ${isMine ? "mine" : "theirs"}`}>
            {!isMine && (
              <div className="msg-avatar">
                {selectedFriend?.profilePic
                  ? <img src={selectedFriend.profilePic} alt="" />
                  : selectedFriend?.username?.[0]?.toUpperCase()
                }
              </div>
            )}
            <div className="bubble-wrap">
              <div className={`bubble ${isMine ? "b-mine" : "b-theirs"}`}>
                {msg.text}
              </div>
              <div className={`msg-meta ${isMine ? "meta-right" : "meta-left"}`}>
                <span className="msg-time">{formatTime(msg.time || msg.createdAt)}</span>
                {isMine && <Tick status={msg.status} />}
              </div>
            </div>
          </div>
        );
      })}

      {typingUser && (
        <div className="msg-row theirs">
          <div className="msg-avatar">
            {selectedFriend?.profilePic
              ? <img src={selectedFriend.profilePic} alt="" />
              : selectedFriend?.username?.[0]?.toUpperCase()
            }
          </div>
          <div className="typing-bubble">
            <span /><span /><span />
          </div>
        </div>
      )}

      <div ref={bottomRef} />
    </div>
  );
}
